function test_transfer($exchange, $skipped_properties, $method, $entry, $requested_code) {
    $format = array(
        'info' => array(),
        'id' => '1234',
        'timestamp' => 1502962946216,
        'datetime' => '2017-08-17 12:42:48.000',
        'currency' => 'USDT',
        'amount' => $exchange->parse_number('1.234'),
        'fromAccount' => 'spot',
        'toAccount' => 'swap',
        'status' => 'ok',
    );
    $empty_allowed_for = ['fromAccount', 'toAccount'];
    assert_structure($exchange, $skipped_properties, $method, $entry, $format, $empty_allowed_for);
    assert_timestamp_and_datetime($exchange, $skipped_properties, $method, $entry, $exchange->milliseconds());
    assert_currency_code($exchange, $skipped_properties, $method, $entry, $entry['currency'], $requested_code);
    //
    assert_in_array($exchange, $skipped_properties, $method, $entry, 'status', ['ok', 'pending', 'failed']);
    assert_greater_or_equal($exchange, $skipped_properties, $method, $entry, 'amount', '0');
}
